/**
 * characters.js — Guess Who! Web Edition Character Database
 *
 * Images use DiceBear API (free, no-auth, SVG avatars).
 * Each category uses a style that fits the theme.
 * https://www.dicebear.com/styles/
 */

// DiceBear avatar generators per style
const avatar = (style, seed, bgColor = '1e293b') =>
  `https://api.dicebear.com/9.x/${style}/svg?seed=${encodeURIComponent(seed)}&backgroundColor=${bgColor}&backgroundType=solid`;

// Style helpers per category
const human = (seed, bg) => avatar('avataaars', seed, bg);       // human cartoon (YouTubers, Actors, Musicians...)
const sport = (seed, bg) => avatar('adventurer', seed, bg);      // adventurer (Footballers, Athletes)
const pixel = (seed, bg) => avatar('pixel-art', seed, bg);       // pixel (Classic, Gamers)
const anime = (seed, bg) => avatar('lorelei', seed, bg);         // stylized (Anime)
const bot = (seed, bg) => avatar('bottts', seed, bg);          // robot/hero (Superheroes)
const fun = (seed, bg) => avatar('fun-emoji', seed, bg);       // emoji face (Memes)
const notion = (seed, bg) => avatar('notionists', seed, bg);      // illustrative (Scientists)

